import React from "react";
import { Link } from "react-router-dom";

const Navbar = () => {
  return (
    <nav className="bg-green-600 text-white px-10 py-4 flex justify-between items-center shadow-md">
      <h1 className="text-2xl font-bold">LeafLens</h1>
      <div className="flex gap-6">
        <Link to="/" className="hover:text-gray-200">Home</Link>
        <Link to="/login" className="hover:text-gray-200">Login</Link>
        <Link
          to="/register"
          className="bg-white text-green-600 px-4 py-2 rounded-lg font-semibold hover:bg-green-100"
        >
          Register
        </Link>
      </div>
    </nav>
  );
};

export default Navbar;
